import type {
  CanvasNodeInteractionState,
  CanvasNodeVisualStatusTone,
} from "@workspace/ui/components/canvas-node/canvas-node";
import type { ReactNode } from "react";

export interface EntryNodeStates {
  name: string;
}

export interface EntryNodeAccessDomain {
  label?: string;
  value: string;
}

export type EntryNodeTargetStatusTone =
  | "accessible"
  | "degraded"
  | "inaccessible"
  | "not-configured"
  | "progressing"
  | "unknown"
  | (string & {});

export interface EntryNodeTargetStatus {
  label: string;
  tone?: EntryNodeTargetStatusTone;
  visualTone?: CanvasNodeVisualStatusTone;
}

export interface EntryNodeTarget {
  id?: string;
  label: string;
  status?: EntryNodeTargetStatus;
  value: string;
}

export type EntryNodeTargetKey = string;

export type EntryNodeCopyTargetHandler = (
  target: EntryNodeTarget,
  index: number
) => Promise<void> | void;

export interface EntryNodeState {
  accessDomain?: EntryNodeAccessDomain;
  copiedTargetKey?: EntryNodeTargetKey | null;
  states: EntryNodeStates;
  targets?: EntryNodeTarget[];
}

export interface EntryNodeActions {
  copyTarget?: EntryNodeCopyTargetHandler;
}

export interface EntryNodeMeta {
  copiedFeedbackMs?: number;
}

export interface EntryNodeContextValue {
  actions: EntryNodeActions;
  meta: EntryNodeMeta;
  state: EntryNodeState;
}

export interface EntryNodeProviderProps {
  children?: ReactNode;
  value: EntryNodeContextValue;
}

export interface EntryNodeRootProps {
  accessDomain?: EntryNodeAccessDomain;
  children?: ReactNode;
  copiedFeedbackMs?: number;
  copiedTargetKey?: EntryNodeTargetKey | null;
  defaultExpanded?: boolean;
  expanded?: boolean;
  interaction?: CanvasNodeInteractionState;
  onCopyTarget?: EntryNodeCopyTargetHandler;
  onExpandedChange?: (expanded: boolean) => void;
  states: EntryNodeStates;
  targets?: EntryNodeTarget[];
}

"use client";

import { createContext, use } from "react";

import type { EntryNodeContextValue } from "./entry-node.types";

export const EntryNodeContext = createContext<EntryNodeContextValue | null>(
  null
);

export function useEntryNode(): EntryNodeContextValue {
  const value = use(EntryNodeContext);

  if (!value) {
    throw new Error(
      "EntryNode: compound components must be used within EntryNode.Root"
    );
  }

  return value;
}

"use client";

import { EntryNodeContext } from "./entry-node.context";
import type { EntryNodeProviderProps } from "./entry-node.types";

export function EntryNodeProvider({ children, value }: EntryNodeProviderProps) {
  return <EntryNodeContext value={value}>{children}</EntryNodeContext>;
}

"use client";

import {
  CANVAS_NODE_DEFAULT_COPIED_FEEDBACK_MS,
  CanvasNodeCopyFeedbackScope,
} from "@workspace/ui/components/canvas-node/canvas-node.copyable-row";
import { CanvasNodeRoot } from "@workspace/ui/components/canvas-node/canvas-node.root";

import { EntryNodeProvider } from "./entry-node.provider";
import type {
  EntryNodeContextValue,
  EntryNodeRootProps,
  EntryNodeTargetKey,
} from "./entry-node.types";

export function EntryNodeRoot({
  accessDomain,
  children,
  copiedFeedbackMs = CANVAS_NODE_DEFAULT_COPIED_FEEDBACK_MS,
  copiedTargetKey,
  defaultExpanded,
  expanded,
  interaction,
  onCopyTarget,
  onExpandedChange,
  states,
  targets,
}: EntryNodeRootProps) {
  return (
    <CanvasNodeRoot
      defaultExpanded={defaultExpanded}
      expanded={expanded}
      interaction={interaction}
      onExpandedChange={onExpandedChange}
    >
      <CanvasNodeCopyFeedbackScope
        copiedFeedbackMs={copiedFeedbackMs}
        copiedKey={copiedTargetKey}
      >
        {({ copiedKey }) => {
          const value: EntryNodeContextValue = {
            actions: {
              copyTarget: onCopyTarget,
            },
            meta: {
              copiedFeedbackMs,
            },
            state: {
              accessDomain,
              copiedTargetKey: copiedKey as EntryNodeTargetKey | null,
              states,
              targets,
            },
          };

          return (
            <EntryNodeProvider value={value}>{children}</EntryNodeProvider>
          );
        }}
      </CanvasNodeCopyFeedbackScope>
    </CanvasNodeRoot>
  );
}

"use client";

import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { cn } from "@workspace/ui/lib/utils";
import { Router } from "lucide-react";

import { useEntryNode } from "./entry-node.context";
import { resolveEntryNodeTargetStatus } from "./entry-node.status";
import { EntryNodeTargetList } from "./entry-node.target";
import type { EntryNodeAccessDomain } from "./entry-node.types";

function getAccessDomain(
  fallbackName: string,
  accessDomain: EntryNodeAccessDomain | undefined
) {
  return (
    accessDomain ?? {
      label: "Access domain",
      value: fallbackName,
    }
  );
}

function useEntryNodeAccessDomain() {
  const {
    state: { accessDomain, states },
  } = useEntryNode();

  return getAccessDomain(states.name, accessDomain);
}

function useEntryNodeResolvedStatus() {
  const {
    state: { targets },
  } = useEntryNode();

  return resolveEntryNodeTargetStatus(targets);
}

export function EntryNodeContent() {
  return (
    <CanvasNode.Card>
      <CanvasNode.Header>
        <EntryNodeHeaderContent />
      </CanvasNode.Header>
      <CanvasNode.Body>
        <EntryNodeTargetList />
      </CanvasNode.Body>
    </CanvasNode.Card>
  );
}

export function EntryNodeHeaderContent({ className }: { className?: string }) {
  return (
    <div className={cn("canvas-node-header-content min-w-0 flex-1", className)}>
      <div className="flex min-w-0 items-center justify-between gap-1.5">
        <EntryNodeAccess />
        <EntryNodeStatus />
      </div>
    </div>
  );
}

export function EntryNodeAccess({ className }: { className?: string }) {
  const accessDomain = useEntryNodeAccessDomain();
  const Icon = Router;

  return (
    <span className={cn("flex min-w-0 flex-1 items-center gap-1.5", className)}>
      <span className="flex size-9 shrink-0 items-center justify-center rounded-lg bg-white/5">
        <Icon aria-hidden className="size-4 text-zinc-50" />
      </span>
      <span className="flex min-w-0 flex-1 flex-col gap-1.5">
        <span
          className="min-w-0 truncate font-normal text-sm text-zinc-50 leading-5"
          title={accessDomain.value}
        >
          {accessDomain.value}
        </span>
        <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
          {accessDomain.label ?? "Access domain"}
        </span>
      </span>
    </span>
  );
}

export function EntryNodeStatus({ className }: { className?: string }) {
  const status = useEntryNodeResolvedStatus();

  return <CanvasNode.Status className={className} status={status} />;
}

import type {
  CanvasNodeStatus,
  CanvasNodeVisualStatusTone,
} from "@workspace/ui/components/canvas-node/canvas-node";

import type {
  EntryNodeTarget,
  EntryNodeTargetStatus,
} from "./entry-node.types";

type EntryNodeTargetStatusBucket =
  | "accessible"
  | "failed"
  | "neutral"
  | "progressing"
  | "warning";

const ACCESSIBLE_TONES = new Set([
  "accessible",
  "available",
  "bound",
  "complete",
  "ready",
  "running",
  "succeeded",
]);

const PROGRESSING_TONES = new Set([
  "binding",
  "creating",
  "pending",
  "progressing",
]);

const WARNING_TONES = new Set(["degraded", "deleting", "stopping"]);

const FAILED_TONES = new Set(["error", "failed", "inaccessible", "unhealthy"]);

const NEUTRAL_TONES = new Set([
  "not-configured",
  "shutdown",
  "stopped",
  "unknown",
]);

function normalizeEntryNodeTargetTone(input: string | undefined) {
  return input
    ?.trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-");
}

function getBucketForVisualTone(
  visualTone: CanvasNodeVisualStatusTone | undefined
): EntryNodeTargetStatusBucket | undefined {
  switch (visualTone) {
    case "positive":
      return "accessible";
    case "progress":
      return "progressing";
    case "warning":
      return "warning";
    case "negative":
      return "failed";
    case "neutral":
      return "neutral";
    default:
      return undefined;
  }
}

function getVisualToneForBucket(
  bucket: EntryNodeTargetStatusBucket
): CanvasNodeVisualStatusTone {
  switch (bucket) {
    case "accessible":
      return "positive";
    case "progressing":
      return "progress";
    case "warning":
      return "warning";
    case "failed":
      return "negative";
    case "neutral":
      return "neutral";
    default:
      return "neutral";
  }
}

function resolveTargetBucket(
  status: EntryNodeTargetStatus | undefined
): EntryNodeTargetStatusBucket {
  const visualBucket = getBucketForVisualTone(status?.visualTone);

  if (visualBucket) {
    return visualBucket;
  }

  const tone = normalizeEntryNodeTargetTone(status?.tone ?? status?.label);

  if (tone && ACCESSIBLE_TONES.has(tone)) {
    return "accessible";
  }

  if (tone && PROGRESSING_TONES.has(tone)) {
    return "progressing";
  }

  if (tone && WARNING_TONES.has(tone)) {
    return "warning";
  }

  if (tone && FAILED_TONES.has(tone)) {
    return "failed";
  }

  if (tone && NEUTRAL_TONES.has(tone)) {
    return "neutral";
  }

  return "neutral";
}

export function resolveEntryNodeTargetVisualStatus(
  status: EntryNodeTargetStatus | undefined
): CanvasNodeStatus {
  const bucket = resolveTargetBucket(status);

  return {
    label: status?.label?.trim() || "Unknown",
    visualTone: getVisualToneForBucket(bucket),
  };
}

function everyTone(
  buckets: EntryNodeTargetStatusBucket[],
  bucket: EntryNodeTargetStatusBucket
) {
  return buckets.every((item) => item === bucket);
}

export function resolveEntryNodeTargetStatus(
  targets: readonly EntryNodeTarget[] | undefined
): CanvasNodeStatus {
  if (!targets || targets.length === 0) {
    return { label: "Not configured", visualTone: "neutral" };
  }

  const buckets = targets.map((target) => resolveTargetBucket(target.status));

  if (everyTone(buckets, "accessible")) {
    return { label: "Accessible", visualTone: "positive" };
  }

  if (everyTone(buckets, "progressing")) {
    return { label: "Progressing", visualTone: "progress" };
  }

  if (everyTone(buckets, "failed")) {
    return { label: "Inaccessible", visualTone: "negative" };
  }

  if (everyTone(buckets, "neutral")) {
    return { label: "Not configured", visualTone: "neutral" };
  }

  return { label: "Degraded", visualTone: "warning" };
}

"use client";

import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { cn } from "@workspace/ui/lib/utils";

import { useEntryNode } from "./entry-node.context";
import { resolveEntryNodeTargetVisualStatus } from "./entry-node.status";
import type { EntryNodeTarget } from "./entry-node.types";

function getTargetKey(target: EntryNodeTarget, index: number) {
  return target.id ?? String(index);
}

export function EntryNodeTargetList({ className }: { className?: string }) {
  const {
    state: { targets = [] },
  } = useEntryNode();
  const scrollable = targets.length > 2;

  if (targets.length === 0) {
    return (
      <div
        className={cn(
          "entry-node-target-empty mt-2.5 flex min-w-0 items-center rounded-lg bg-zinc-950/20 px-2.5 text-muted-foreground text-xs leading-4",
          className
        )}
        data-slot="entry-node-target-empty"
      >
        Not configured
      </div>
    );
  }

  return (
    <div
      className={cn(
        "entry-node-target-list mt-2.5 flex min-w-0 flex-col gap-2",
        className
      )}
      data-scrollable={scrollable || undefined}
      data-slot="entry-node-target-list"
    >
      {targets.map((target, index) => (
        <EntryNodeTargetRow
          index={index}
          key={getTargetKey(target, index)}
          target={target}
        />
      ))}
    </div>
  );
}

export function EntryNodeTargetRow({
  className,
  index,
  target,
}: {
  className?: string;
  index: number;
  target: EntryNodeTarget;
}) {
  const { actions } = useEntryNode();
  const rowKey = getTargetKey(target, index);
  const visualStatus = resolveEntryNodeTargetVisualStatus(target.status);

  return (
    <CanvasNode.CopyableRow
      className={cn(
        "entry-node-target-row relative flex min-w-0 items-start gap-2 rounded-lg bg-zinc-950/20 p-2.5 transition-colors",
        className
      )}
      copyAriaLabel={`Copy ${target.label} ${target.value}`}
      copyValue={target.value}
      data-slot="entry-node-target-row"
      onCopy={
        actions.copyTarget
          ? () => actions.copyTarget?.(target, index)
          : undefined
      }
      rowKey={rowKey}
      title={target.value}
    >
      {({ copied }) => (
        <div
          aria-hidden
          className="entry-node-target-content pointer-events-none relative z-10 flex min-w-0 flex-1 flex-col gap-2"
        >
          <div className="flex min-w-0 items-center gap-1.5">
            <CanvasNode.StatusDot size="small" status={visualStatus} />
            <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
              {target.label}
            </span>
          </div>
          <span
            className="flex h-7 w-full min-w-0 items-center justify-between gap-2 py-1.5 text-left font-normal text-xs text-zinc-50 leading-4"
            data-copied={copied ? "true" : undefined}
            data-slot="entry-node-target-value"
            title={target.value}
          >
            <span className="min-w-0 truncate">{target.value}</span>
            <CanvasNode.CopyableRowIndicator />
          </span>
        </div>
      )}
    </CanvasNode.CopyableRow>
  );
}

.entry-node-target-list {
  max-height: calc((var(--spacing) * 18 * 2) + (var(--spacing) * 2));
  overflow-y: auto;
  scrollbar-width: none;
}

.entry-node-target-list::-webkit-scrollbar {
  display: none;
}

.entry-node-target-list:not([data-scrollable]) {
  overflow: hidden;
}

.entry-node-target-row,
.entry-node-target-empty {
  min-height: calc(var(--spacing) * 18);
}

